{"code":"import json
import random

with open(locals()['var_function-call-9402959819383380444'], 'r') as f:
    metadata_list = json.load(f)

region_ids = {}
for row in metadata_list:
    reg = row['region']
    if reg not in region_ids:
        region_ids[reg] = []
    region_ids[reg].append(str(row['article_id']))

region_stats = {}
sample_ids = []

# We'll take up to 50 samples per region
SAMPLE_SIZE = 50

for reg, ids in region_ids.items():
    count = len(ids)
    # Random sample
    if count > SAMPLE_SIZE:
        s = random.sample(ids, SAMPLE_SIZE)
    else:
        s = ids
    sample_ids.extend(s)
    region_stats[reg] = {"total_count": count, "sample_size": len(s), "sample_ids": s}

print("__RESULT__:")
print(json.dumps({
    "region_stats": region_stats,
    "all_sample_ids": sample_ids
}))"}

